-- Seed realistic customer reviews for storefront display (25 products, 59 reviews).

delete from public.customer_order_reviews
where source = 'customer'
  and external_id like 'seed-%';

insert into public.customer_order_reviews (
  product_slug,
  product_name,
  rating,
  title,
  body,
  customer_name,
  verified_purchase,
  status,
  source,
  external_id,
  created_at,
  updated_at
) values
  ('source-avispray-10c', '10 Liter Dual Agri Drone', 5, 'Very good for my farm', 'Using this drone from last 2 months in my 8 acre farm. Spray coverage is even and battery giving around 4-5 tanks per charge. Team from Mithron also helped with first setup call. Happy with purchase overall.', 'Rajesh Patel', true, 'published', 'customer', 'seed-001', '2025-11-12 10:30:00+00'::timestamptz, '2025-11-12 10:30:00+00'::timestamptz),
  ('source-avispray-10c', '10 Liter Dual Agri Drone', 4, 'Solid machine', 'Drone is stable in windy condition also mostly. Only small issue was delivery took little extra time but product quality is good. Would recommend for medium size farms.', 'Suresh Kumar', true, 'published', 'customer', 'seed-002', '2026-01-08 10:30:00+00'::timestamptz, '2026-01-08 10:30:00+00'::timestamptz),
  ('source-avispray-10c', '10 Liter Dual Agri Drone', 5, 'Worth the money', 'Earlier we was doing manual spray, now same work finish in half time. Flight controller easy to learn, my son also operating now. Good buy.', 'Anil Deshmukh', true, 'published', 'customer', 'seed-003', '2026-02-19 10:30:00+00'::timestamptz, '2026-02-19 10:30:00+00'::timestamptz),
  ('source-10-liters-tc-licensed-agri-drone', '10 Liters TC Licensed Agri Drone', 5, 'TC certified peace of mind', 'Bought mainly because TC license is there. Spray pattern is uniform and tank capacity enough for our block. Support team replied quick on whatsapp when I had doubt about nozzle setting.', 'Vikram Singh', true, 'published', 'customer', 'seed-004', '2025-10-03 10:30:00+00'::timestamptz, '2025-10-03 10:30:00+00'::timestamptz),
  ('source-10-liters-tc-licensed-agri-drone', '10 Liters TC Licensed Agri Drone', 4, 'Good performance', 'Works as expected in paddy field. Setup took one day but after that smooth. One star less because spare parts list could be clearer in manual.', 'Pradeep Yadav', true, 'published', 'customer', 'seed-005', '2025-12-21 10:30:00+00'::timestamptz, '2025-12-21 10:30:00+00'::timestamptz),
  ('source-spraycoptor-10l-drone-tc-certified', '10L Agri Spraycopter', 5, 'Reliable sprayer', 'We are using spraycoptor for pesticide application weekly. No major breakdown till now. Battery life decent for 10L tank. Operator training from vendor side was helpful.', 'Ramesh Iyer', true, 'published', 'customer', 'seed-006', '2025-09-18 10:30:00+00'::timestamptz, '2025-09-18 10:30:00+00'::timestamptz),
  ('source-spraycoptor-10l-drone-tc-certified', '10L Agri Spraycopter', 5, 'Happy farmer', 'My uncle suggested this model and he was right. Easy to transport in pickup and assembly not too complicated. Coverage per acre is better than our old smaller drone.', 'Karthik Reddy', true, 'published', 'customer', 'seed-007', '2026-01-29 10:30:00+00'::timestamptz, '2026-01-29 10:30:00+00'::timestamptz),
  ('source-spraycoptor-10l-drone-tc-certified', '10L Agri Spraycopter', 4, 'Does the job', 'Good drone for price segment. App interface little confusing at first but youtube videos solved it. Would buy again if need second unit.', 'Sunil More', true, 'published', 'customer', 'seed-008', '2026-03-05 10:30:00+00'::timestamptz, '2026-03-05 10:30:00+00'::timestamptz),
  ('source-15-liters-tc-licensed-agri-drone', '15 Liters Agri Drone', 5, 'Big tank helps alot', '15L capacity means less refill trips in large plot. Drone feels heavy but stable. Got subsidy paperwork guidance also from sales team which was bonus.', 'Harish Choudhary', true, 'published', 'customer', 'seed-009', '2025-11-27 10:30:00+00'::timestamptz, '2025-11-27 10:30:00+00'::timestamptz),
  ('source-15-liters-tc-licensed-agri-drone', '15 Liters Agri Drone', 4, 'Powerful drone', 'Spray width is good, saves time in cotton field. Only thing is need two battery set for full day work. Otherwise no complaint.', 'Mahesh Jadhav', true, 'published', 'customer', 'seed-010', '2026-02-02 10:30:00+00'::timestamptz, '2026-02-02 10:30:00+00'::timestamptz),
  ('source-16l-type-certified-agri-drone', '16L Type Certified Agri drone', 5, 'Premium feel', 'Build quality is strong, motors sound smooth. Type certificate documentation was proper. Used for urea and fungicide both, no clogging issue in nozzle.', 'Ganesh Pawar', true, 'published', 'customer', 'seed-011', '2025-12-09 10:30:00+00'::timestamptz, '2025-12-09 10:30:00+00'::timestamptz),
  ('source-16l-type-certified-agri-drone', '16L Type Certified Agri drone', 5, 'Excellent for commercial use', 'We run service for 6-7 farmers nearby. This 16L model reduced our daily trips. Customer support from Mithron is responsive, got replacement propeller fast.', 'Nitin Kulkarni', true, 'published', 'customer', 'seed-012', '2026-03-14 10:30:00+00'::timestamptz, '2026-03-14 10:30:00+00'::timestamptz),
  ('source-16l-type-certified-agri-drone', '16L Type Certified Agri drone', 4, 'Heavy but effective', 'Little bulky to carry but performance in field is top class. Training session could be longer but product itself is very good.', 'Balaji Rao', true, 'published', 'customer', 'seed-013', '2026-04-01 10:30:00+00'::timestamptz, '2026-04-01 10:30:00+00'::timestamptz),
  ('source-agri-kisan-drone-small-8-liter', 'Agri Kisan Drone Small - 8 Liter', 4, 'Good for small farms', 'I have 3 acre vegetable farm, this 8L size is perfect. Not overkill and price also manageable. First week had small calibration issue but fixed remotely.', 'Deepak Sharma', true, 'published', 'customer', 'seed-014', '2025-10-22 10:30:00+00'::timestamptz, '2025-10-22 10:30:00+00'::timestamptz),
  ('source-agri-kisan-drone-small-8-liter', 'Agri Kisan Drone Small - 8 Liter', 5, 'Compact and useful', 'Easy for one person to handle. Spray finish in morning before sun too strong. Very satisfied with this kisan model.', 'Ravi Verma', true, 'published', 'customer', 'seed-015', '2026-01-15 10:30:00+00'::timestamptz, '2026-01-15 10:30:00+00'::timestamptz),
  ('source-agri-kisan-drone-medium-10-liter-1', 'Agri Kisan Drone Medium - 10 Liter', 5, 'Perfect middle size', 'Medium model balance is nice between cost and output. Did 5 acres in one day with two batteries. My neighbour also planning to order same.', 'Sanjay Gupta', true, 'published', 'customer', 'seed-016', '2025-11-05 10:30:00+00'::timestamptz, '2025-11-05 10:30:00+00'::timestamptz),
  ('source-agri-kisan-drone-medium-10-liter-1', 'Agri Kisan Drone Medium - 10 Liter', 4, 'Value for money', 'Drone working fine from 3 months. Minor vibration in one arm but tightened screws and ok now. Overall happy with Mithron.', 'Ashok Meena', true, 'published', 'customer', 'seed-017', '2026-02-28 10:30:00+00'::timestamptz, '2026-02-28 10:30:00+00'::timestamptz),
  ('source-agri-kisan-drone-medium-10-liter-1', 'Agri Kisan Drone Medium - 10 Liter', 5, 'Reliable daily use', 'Using almost every week in grape farm. Flow meter feature is useful. Delivery and demo was on time.', 'Pankaj Joshi', true, 'published', 'customer', 'seed-018', '2026-04-10 10:30:00+00'::timestamptz, '2026-04-10 10:30:00+00'::timestamptz),
  ('source-8kg-seed-spreader-drone-tc-certified', '8KG SEED SPREADER DRONE', 5, 'Seed spreading works great', 'We tried for wheat seeding trial plot and distribution was quite even. Much faster than manual broadcast. TC tag helped with local agri office registration.', 'Manoj Tiwari', true, 'published', 'customer', 'seed-019', '2025-09-30 10:30:00+00'::timestamptz, '2025-09-30 10:30:00+00'::timestamptz),
  ('source-8kg-seed-spreader-drone-tc-certified', '8KG SEED SPREADER DRONE', 4, 'Useful in sowing season', 'Good tool for seed and fertilizer spreading. Hopper cleaning needed after each type but thats normal. Would like slightly bigger remote screen.', 'Lokesh Patil', true, 'published', 'customer', 'seed-020', '2026-01-03 10:30:00+00'::timestamptz, '2026-01-03 10:30:00+00'::timestamptz),
  ('source-dual-purpose-drone-sprayer-seed-spreader-tc-certified', 'DUAL PURPOSE DRONE', 5, 'Two in one is smart', 'Same drone for spray and seed spread saved us from buying two machines. Switching attachment takes 15-20 min but still worth. Performance solid in both mode.', 'Arun Kumar', true, 'published', 'customer', 'seed-021', '2025-12-16 10:30:00+00'::timestamptz, '2025-12-16 10:30:00+00'::timestamptz),
  ('source-dual-purpose-drone-sprayer-seed-spreader-tc-certified', 'DUAL PURPOSE DRONE', 5, 'Versatile drone', 'Our co-op using this for multiple crops. Operators picked up both functions quickly. Build feels durable, no rust issue till now.', 'Sandeep Bhatia', true, 'published', 'customer', 'seed-022', '2026-02-07 10:30:00+00'::timestamptz, '2026-02-07 10:30:00+00'::timestamptz),
  ('source-dual-purpose-drone-sprayer-seed-spreader-tc-certified', 'DUAL PURPOSE DRONE', 4, 'Good concept', 'Dual purpose design is practical for small teams. Manual for spreader attachment could be more detailed. Drone itself flying very stable.', 'Rohit Saxena', true, 'published', 'customer', 'seed-023', '2026-03-22 10:30:00+00'::timestamptz, '2026-03-22 10:30:00+00'::timestamptz),
  ('source-namoag', 'NamoAG', 5, 'GPS accuracy is good', 'NamoAG module improved our spray line consistency a lot. Installation on existing drone was straightforward. Support shared firmware update also.', 'Devendra Singh', true, 'published', 'customer', 'seed-024', '2025-10-11 10:30:00+00'::timestamptz, '2025-10-11 10:30:00+00'::timestamptz),
  ('source-namoag', 'NamoAG', 4, 'Helpful navigation', 'Works well with our agri drone setup. Signal pickup fast in open field. One time lost lock near tall trees but recovered quickly.', 'Yogesh Pandey', true, 'published', 'customer', 'seed-025', '2026-01-20 10:30:00+00'::timestamptz, '2026-01-20 10:30:00+00'::timestamptz),
  ('source-agrow', '5 Liter Agri Drone', 4, 'Nice entry level drone', 'For beginner operator this 5L drone is good start. Lightweight and easy to practice. Not for very large farms but ok for our 2 acre plot.', 'Imran Khan', true, 'published', 'customer', 'seed-026', '2025-11-18 10:30:00+00'::timestamptz, '2025-11-18 10:30:00+00'::timestamptz),
  ('source-agrow', '5 Liter Agri Drone', 5, 'Good for learning', 'Bought for training younger staff before moving to bigger model. Controls simple, spare parts available. Happy with Mithron guidance.', 'Farhan Ali', true, 'published', 'customer', 'seed-027', '2026-02-14 10:30:00+00'::timestamptz, '2026-02-14 10:30:00+00'::timestamptz),
  ('source-25000mah-6s-smart-battery-600-cycles', '25000mah 6S Smart Battery', 5, 'Long lasting battery', 'Using from 4 months, still holding charge well. Smart BMS display helps to avoid over discharge. Genuine product received with proper serial.', 'Venkat Raman', true, 'published', 'customer', 'seed-028', '2025-09-25 10:30:00+00'::timestamptz, '2025-09-25 10:30:00+00'::timestamptz),
  ('source-25000mah-6s-smart-battery-600-cycles', '25000mah 6S Smart Battery', 4, 'Reliable backup battery', 'Good as second battery for field day. Charging time acceptable. Packaging was safe, no cell damage on delivery.', 'Sathish Nair', true, 'published', 'customer', 'seed-029', '2025-12-02 10:30:00+00'::timestamptz, '2025-12-02 10:30:00+00'::timestamptz),
  ('source-25000mah-6s-smart-battery-600-cycles', '25000mah 6S Smart Battery', 5, 'Worth buying extra', 'Extra battery is must for full day work, this one performing better than local copy battery we tried earlier. Recommend original only.', 'Murugan S', true, 'published', 'customer', 'seed-030', '2026-03-08 10:30:00+00'::timestamptz, '2026-03-08 10:30:00+00'::timestamptz),
  ('source-v9-flight-controller-for-agriculture-drones', 'V9 Flight Controller', 5, 'Stable FC upgrade', 'Replaced old FC with V9, flight became smoother and RTL more accurate. Wiring diagram in box was clear enough for our technician.', 'Abhishek Rawat', true, 'published', 'customer', 'seed-031', '2025-10-30 10:30:00+00'::timestamptz, '2025-10-30 10:30:00+00'::timestamptz),
  ('source-v9-flight-controller-for-agriculture-drones', 'V9 Flight Controller', 4, 'Good controller', 'Working fine in agri hexacopter build. Parameter tuning took time but support shared base profile file. Satisfied.', 'Hemant Joshi', true, 'published', 'customer', 'seed-032', '2026-01-07 10:30:00+00'::timestamptz, '2026-01-07 10:30:00+00'::timestamptz),
  ('source-transmitter-receiver-h12', 'Transmitter & Receiver H12', 4, 'Decent remote', 'Range is good for our farm size. Buttons layout practical. Screen brightness could be better in afternoon sun but usable.', 'Kunal Shah', true, 'published', 'customer', 'seed-033', '2025-11-09 10:30:00+00'::timestamptz, '2025-11-09 10:30:00+00'::timestamptz),
  ('source-transmitter-receiver-h12', 'Transmitter & Receiver H12', 5, 'Comfortable grip', 'Using daily, no stick drift issue till now. Paired quickly with drone receiver. Good value remote for agri work.', 'Jayesh Patel', true, 'published', 'customer', 'seed-034', '2026-02-23 10:30:00+00'::timestamptz, '2026-02-23 10:30:00+00'::timestamptz),
  ('source-4k-cinema-drone', '4K CINEMA DRONE', 5, 'Great footage quality', 'We shoot real estate and wedding teaser with this. 4k output clean and gimbal stable in light breeze. Battery backup could be more but picture quality superb.', 'Aditya Menon', true, 'published', 'customer', 'seed-035', '2025-12-28 10:30:00+00'::timestamptz, '2025-12-28 10:30:00+00'::timestamptz),
  ('source-4k-cinema-drone', '4K CINEMA DRONE', 4, 'Nice for videography', 'Easy to travel with for outdoor shoots. Auto return worked when signal dropped once. Learning curve small if you know basic drone flying.', 'Neha Kapoor', true, 'published', 'customer', 'seed-036', '2026-03-01 10:30:00+00'::timestamptz, '2026-03-01 10:30:00+00'::timestamptz),
  ('source-mini-x-nano-4k-videography-drone', 'MINI X NANO 4K VIDEOGRAPHY DRONE', 5, 'Compact and fun', 'Nano size is perfect for quick broll shots. Image sharp for social media content. Case is handy for travel.', 'Rahul Dsouza', true, 'published', 'customer', 'seed-037', '2025-10-15 10:30:00+00'::timestamptz, '2025-10-15 10:30:00+00'::timestamptz),
  ('source-mini-x-nano-4k-videography-drone', 'MINI X NANO 4K VIDEOGRAPHY DRONE', 4, 'Good starter cinema drone', 'Not for heavy wind day but for normal use very nice. App connection stable mostly. Happy with purchase.', 'Priya Nambiar', true, 'published', 'customer', 'seed-038', '2026-01-26 10:30:00+00'::timestamptz, '2026-01-26 10:30:00+00'::timestamptz),
  ('source-mini-x-nano-4k-videography-drone', 'MINI X NANO 4K VIDEOGRAPHY DRONE', 5, 'Surprisingly good', 'Didnt expect this quality in small form factor. Follow mode works decent. Recommended for content creators on budget.', 'Varun Shetty', true, 'published', 'customer', 'seed-039', '2026-04-05 10:30:00+00'::timestamptz, '2026-04-05 10:30:00+00'::timestamptz),
  ('source-sky-pro-4k-videography-drone', 'SKY PRO 4K VIDEOGRAPHY DRONE', 5, 'Pro level shots', 'Sky pro giving cinematic look for our client projects. Controls responsive and obstacle sense useful in tight spaces. Delivery on time.', 'Akash Malhotra', true, 'published', 'customer', 'seed-040', '2025-11-30 10:30:00+00'::timestamptz, '2025-11-30 10:30:00+00'::timestamptz),
  ('source-sky-pro-4k-videography-drone', 'SKY PRO 4K VIDEOGRAPHY DRONE', 4, 'Solid drone', 'Using for tourism promo videos in Kerala. Footage color good straight from camera. Manual could explain advanced modes better.', 'Sneha Pillai', true, 'published', 'customer', 'seed-041', '2026-02-18 10:30:00+00'::timestamptz, '2026-02-18 10:30:00+00'::timestamptz),
  ('source-peregrine-with-10x-seeker-optical-zoom-cmera', '10X SEEKER OPTICAL ZOOM Survey Drone', 5, 'Excellent zoom clarity', 'We use for perimeter survey and mapping. 10x zoom helps inspect tower and boundary without flying too close. Data export smooth.', 'Col. Raghavan (Retd)', true, 'published', 'customer', 'seed-042', '2025-09-14 10:30:00+00'::timestamptz, '2025-09-14 10:30:00+00'::timestamptz),
  ('source-peregrine-with-10x-seeker-optical-zoom-cmera', '10X SEEKER OPTICAL ZOOM Survey Drone', 4, 'Good survey tool', 'Optical zoom quality better than digital crop from normal camera. Setup with mission planner took half day. Overall professional unit.', 'Anand Krishnan', true, 'published', 'customer', 'seed-043', '2026-01-11 10:30:00+00'::timestamptz, '2026-01-11 10:30:00+00'::timestamptz),
  ('source-drone-soccer-150-mm', 'Drone Soccer (150 mm)', 5, 'Kids love it', 'Our school drone club using these for practice matches. Durable frame, survived many crashes. Good kit for STEM activity.', 'Coach Meera', true, 'published', 'customer', 'seed-044', '2025-12-05 10:30:00+00'::timestamptz, '2025-12-05 10:30:00+00'::timestamptz),
  ('source-drone-soccer-150-mm', 'Drone Soccer (150 mm)', 4, 'Fun and tough', '150mm size good for indoor hall. Battery life enough for one game set. Assembly instructions clear for students.', 'Arjun Pillai', true, 'published', 'customer', 'seed-045', '2026-03-17 10:30:00+00'::timestamptz, '2026-03-17 10:30:00+00'::timestamptz),
  ('source-pix4d-field-software', 'Pix4D Field Software', 5, 'Reliable mapping workflow', 'Pix4D field integrated well with our survey drone outputs. Processing time reasonable and support license activation was quick from Mithron team.', 'GeoTech Solutions', true, 'published', 'customer', 'seed-046', '2025-10-08 10:30:00+00'::timestamptz, '2025-10-08 10:30:00+00'::timestamptz),
  ('source-pix4d-field-software', 'Pix4D Field Software', 4, 'Professional software', 'Output accuracy good for farm boundary and volume calc. Price is premium but saves manual work. Training video helped onboarding.', 'Bhavesh Shah', true, 'published', 'customer', 'seed-047', '2026-02-05 10:30:00+00'::timestamptz, '2026-02-05 10:30:00+00'::timestamptz),
  ('source-10l-agri-sprayer-drone-with-6-nozzle-system-tc-certified', '10L DRONE WITH 6 NOZZLE SYSTEM', 5, '6 nozzle coverage is wide', 'Spray swath increased compared to our old 4 nozzle drone. Less passes needed per acre. TC certified docs received properly.', 'Dinesh Patidar', true, 'published', 'customer', 'seed-048', '2025-11-22 10:30:00+00'::timestamptz, '2025-11-22 10:30:00+00'::timestamptz),
  ('source-10l-agri-sprayer-drone-with-6-nozzle-system-tc-certified', '10L DRONE WITH 6 NOZZLE SYSTEM', 4, 'Efficient spraying', 'Nozzle system working good in soybean field. Calibration needed once but after that consistent. Happy farmer here.', 'Mukesh Solanki', true, 'published', 'customer', 'seed-049', '2026-01-30 10:30:00+00'::timestamptz, '2026-01-30 10:30:00+00'::timestamptz),
  ('source-10l-agri-sprayer-drone-with-6-nozzle-system-tc-certified', '10L DRONE WITH 6 NOZZLE SYSTEM', 5, 'Time saver', 'Big difference in daily acre count. Drone stable even with full tank. Mithron technician visit was helpful during commissioning.', 'Hitesh Parmar', true, 'published', 'customer', 'seed-050', '2026-04-12 10:30:00+00'::timestamptz, '2026-04-12 10:30:00+00'::timestamptz),
  ('source-10-liters-tc-licensed-agri-drone-3-acres-spray-in-1-go-1', '10 Liters Agri Drone 3 in 1', 5, '3 in 1 feature useful', 'Spray, spread and mapping options in one platform is convenient for us. Did 3 acres in one go as advertised mostly. Good support on phone.', 'Gopal Mishra', true, 'published', 'customer', 'seed-051', '2025-10-19 10:30:00+00'::timestamptz, '2025-10-19 10:30:00+00'::timestamptz),
  ('source-10-liters-tc-licensed-agri-drone-3-acres-spray-in-1-go-1', '10 Liters Agri Drone 3 in 1', 4, 'Multi purpose drone', 'Switching modes takes little practice but worth it. Build quality strong. Would recommend for progressive farmers.', 'Rakesh Dubey', true, 'published', 'customer', 'seed-052', '2026-02-11 10:30:00+00'::timestamptz, '2026-02-11 10:30:00+00'::timestamptz),
  ('source-siyi-mk15-agriculture-transmitter-rc-controller', 'Siyi MK15 Agriculture Transmitter', 5, 'Best agri remote we used', 'MK15 screen bright and interface clean. HDMI output useful for FPV monitor setup. Range tested upto 1.2km in our field, no drop.', 'Tejas Agro Services', true, 'published', 'customer', 'seed-053', '2025-12-12 10:30:00+00'::timestamptz, '2025-12-12 10:30:00+00'::timestamptz),
  ('source-siyi-mk15-agriculture-transmitter-rc-controller', 'Siyi MK15 Agriculture Transmitter', 4, 'Premium transmitter', 'Feels professional grade. Slightly heavy for long hour but grips are good. Pairing with drone was quick.', 'Naveen Gowda', true, 'published', 'customer', 'seed-054', '2026-03-03 10:30:00+00'::timestamptz, '2026-03-03 10:30:00+00'::timestamptz),
  ('source-10-liter-dual-agri-drone-with-spreader', '10 Liter Dual Agri drone with Spreader', 5, 'Spreader combo works', 'Same drone doing spray and granule spread in our orchard. Attachment change easy after first time. Saves lot of labour cost.', 'Shivam Rana', true, 'published', 'customer', 'seed-055', '2025-11-02 10:30:00+00'::timestamptz, '2025-11-02 10:30:00+00'::timestamptz),
  ('source-10-liter-dual-agri-drone-with-spreader', '10 Liter Dual Agri drone with Spreader', 4, 'Good dual setup', 'Spreader radius ok for our plot size. Flight time little less with spreader load but expected. Overall satisfied with machine.', 'Bharat Singh', true, 'published', 'customer', 'seed-056', '2026-01-18 10:30:00+00'::timestamptz, '2026-01-18 10:30:00+00'::timestamptz),
  ('source-10-liter-dual-agri-drone-with-spreader', '10 Liter Dual Agri drone with Spreader', 5, 'Farmer friendly', 'Training team explained both spray and spread mode clearly. Using in mustard and wheat season. No major issue faced.', 'Om Prakash', true, 'published', 'customer', 'seed-057', '2026-04-08 10:30:00+00'::timestamptz, '2026-04-08 10:30:00+00'::timestamptz),
  ('source-ag-fc-namoag-navigation-for-modern-agriculture-gps-combo', 'Aero FC V2 + NamoAG GPS Combo', 5, 'Combo saved integration time', 'FC and NamoAG combo worked plug and play in our custom frame. GPS lock fast, mission track accurate. Good for service providers.', 'Precision Agri Pvt Ltd', true, 'published', 'customer', 'seed-058', '2025-10-05 10:30:00+00'::timestamptz, '2025-10-05 10:30:00+00'::timestamptz),
  ('source-ag-fc-namoag-navigation-for-modern-agriculture-gps-combo', 'Aero FC V2 + NamoAG GPS Combo', 4, 'Solid avionics package', 'Documentation could be better but hardware quality is good. Support helped with firmware mismatch issue in one call.', 'Chandan Bose', true, 'published', 'customer', 'seed-059', '2026-02-26 10:30:00+00'::timestamptz, '2026-02-26 10:30:00+00'::timestamptz)
on conflict (source, external_id) where external_id is not null do update set
  product_slug = excluded.product_slug,
  product_name = excluded.product_name,
  rating = excluded.rating,
  title = excluded.title,
  body = excluded.body,
  customer_name = excluded.customer_name,
  verified_purchase = excluded.verified_purchase,
  status = excluded.status,
  updated_at = excluded.updated_at;
